"use client";

import { useRef, useState, useEffect, useMemo } from "react";
import { useFrame } from "@react-three/fiber";
import * as THREE from "three";
import gsap from "gsap";
import { particleStore } from "@/lib/particleStore";
import { fibonacciSphere } from "@/lib/sphereSampler";
import { particleVertexShader } from "@/shaders/particleVert";
import { particleFragmentShader } from "@/shaders/particleFrag";

const PARTICLE_COUNT = 8000;

// ── Color palette — ambient phase (white / icy blue / violet) ─────────────────
const PALETTE = [
  new THREE.Color("#ffffff"),
  new THREE.Color("#d8eeff"),
  new THREE.Color("#b0ccff"),
  new THREE.Color("#c4b5fd"),
  new THREE.Color("#ffffff"),
];
const PALETTE_W = [0.45, 0.65, 0.82, 0.95, 1.00];

function pickColor(): THREE.Color {
  const r = Math.random();
  for (let i = 0; i < PALETTE_W.length; i++) {
    if (r < PALETTE_W[i]) return PALETTE[i];
  }
  return PALETTE[0];
}

// ── Build ambient starting positions (cloud around center) ────────────────────
function buildAmbientPositions(count: number): Float32Array {
  const pos = new Float32Array(count * 3);
  for (let i = 0; i < count; i++) {
    // Three density bands for a layered, organic cloud
    const r = Math.random();
    const spread = r < 0.55 ? 0.8 : r < 0.85 ? 2.0 : 4.5;
    pos[i * 3]     = (Math.random() - 0.5) * 10 * spread * 0.55;
    pos[i * 3 + 1] = (Math.random() - 0.5) *  3 * spread * 0.4;
    pos[i * 3 + 2] = (Math.random() - 0.5) *  2 * spread;
  }
  return pos;
}

// ── Build per-particle data ───────────────────────────────────────────────────
function buildParticleData(ambientPos: Float32Array) {
  const spherePos = fibonacciSphere(PARTICLE_COUNT, 2.2, 0.8); // shifted up
  const freePos   = new Float32Array(PARTICLE_COUNT * 3);
  const colors    = new Float32Array(PARTICLE_COUNT * 3);
  const sizes     = new Float32Array(PARTICLE_COUNT);
  const randoms   = new Float32Array(PARTICLE_COUNT);

  for (let i = 0; i < PARTICLE_COUNT; i++) {
    const ax = ambientPos[i * 3];
    const ay = ambientPos[i * 3 + 1];

    // Free-flight: spread upward from ambient position
    freePos[i * 3]     = ax + (Math.random() - 0.5) * 14;
    freePos[i * 3 + 1] = ay + 2 + Math.random() * 8;
    freePos[i * 3 + 2] = (Math.random() - 0.5) * 5;

    const c = pickColor();
    colors[i * 3]     = c.r;
    colors[i * 3 + 1] = c.g;
    colors[i * 3 + 2] = c.b;

    sizes[i] = Math.random() < 0.95
      ? 0.8 + Math.random() * 1.0
      : 2.5 + Math.random() * 2.0; // sparkles

    randoms[i] = Math.random();
  }

  return { spherePos, freePos, colors, sizes, randoms };
}

// ── Component ─────────────────────────────────────────────────────────────────
export default function ParticleSystem() {
  const geomRef  = useRef<THREE.BufferGeometry>(null!);
  const matRef   = useRef<THREE.ShaderMaterial>(null!);
  const introRef = useRef({ value: 0 });

  const pixelRatio = useMemo(() =>
    typeof window !== "undefined" ? Math.min(window.devicePixelRatio, 2) : 1
  , []);

  const [ready, setReady] = useState(false);

  // ── Initialize client-side ────────────────────────────────────────────────
  useEffect(() => {
    const ambientPos = buildAmbientPositions(PARTICLE_COUNT);
    const { spherePos, freePos, colors, sizes, randoms } =
      buildParticleData(ambientPos);

    const g = geomRef.current;
    g.setAttribute("position",   new THREE.BufferAttribute(ambientPos, 3));
    g.setAttribute("aTextPos",   new THREE.BufferAttribute(ambientPos, 3)); // "resting" state
    g.setAttribute("aFreePos",   new THREE.BufferAttribute(freePos,    3));
    g.setAttribute("aSpherePos", new THREE.BufferAttribute(spherePos,  3));
    g.setAttribute("aColor",     new THREE.BufferAttribute(colors,     3));
    g.setAttribute("aSize",      new THREE.BufferAttribute(sizes,      1));
    g.setAttribute("aRandom",    new THREE.BufferAttribute(randoms,    1));

    setReady(true);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // ── Intro: particles rise from below into ambient positions ───────────────
  useEffect(() => {
    if (!ready) return;
    gsap.fromTo(
      introRef.current,
      { value: 0 },
      {
        value: 1,
        duration: 1.8,
        delay: 0.2,
        ease: "power2.out",
        onUpdate: () => {
          if (matRef.current) {
            matRef.current.uniforms.uIntroProgress.value = introRef.current.value;
          }
        },
      }
    );
  }, [ready]);

  // ── Mouse tracking (bypasses pointer-events:none canvas) ─────────────────
  const mouseRef = useRef({ x: 0, y: 0 });
  useEffect(() => {
    const onMove = (e: MouseEvent) => {
      mouseRef.current.x =  (e.clientX / window.innerWidth)  * 2 - 1;
      mouseRef.current.y = -(e.clientY / window.innerHeight) * 2 + 1;
    };
    window.addEventListener("mousemove", onMove, { passive: true });
    return () => window.removeEventListener("mousemove", onMove);
  }, []);

  // ── Render loop ───────────────────────────────────────────────────────────
  useFrame((state) => {
    if (!matRef.current) return;
    const u = matRef.current.uniforms;
    u.uTime.value             = state.clock.elapsedTime;
    u.uScrollProgress.value   = particleStore.scrollProgress;
    u.uAssemblyProgress.value = particleStore.assemblyProgress;

    // Camera parallax
    const { camera } = state;
    camera.position.x += (mouseRef.current.x * 0.5 - camera.position.x) * 0.04;
    camera.position.y += (mouseRef.current.y * 0.25 - camera.position.y) * 0.04;
    camera.lookAt(0, 0, 0);
  });

  return (
    <points>
      <bufferGeometry ref={geomRef} />
      <shaderMaterial
        ref={matRef}
        vertexShader={particleVertexShader}
        fragmentShader={particleFragmentShader}
        transparent
        depthWrite={false}
        blending={THREE.AdditiveBlending}
        uniforms={{
          uTime:             { value: 0 },
          uIntroProgress:    { value: 0 },
          uScrollProgress:   { value: 0 },
          uAssemblyProgress: { value: 0 },
          uPixelRatio:       { value: pixelRatio },
        }}
      />
    </points>
  );
}
