"use client";

import { Suspense } from "react";
import { Canvas } from "@react-three/fiber";
import { EffectComposer, Bloom } from "@react-three/postprocessing";
import { KernelSize } from "postprocessing";
import * as THREE from "three";
import ParticleSystem from "./ParticleSystem";

export default function ThreeScene() {
  return (
    <div
      data-canvas-wrapper=""
      style={{
        position: "fixed",
        inset: 0,
        zIndex: 0,
        background: "#000510",
        pointerEvents: "none",   // ← never block scroll / mouse events
      }}
    >
      <Canvas
        camera={{ position: [0, 0, 6], fov: 60, near: 0.1, far: 100 }}
        dpr={[1, 2]}
        style={{ pointerEvents: "none" }}   // ← canvas element itself: no event blocking
        gl={{
          antialias: false,
          alpha: false,
          powerPreference: "high-performance",
          toneMapping: THREE.ACESFilmicToneMapping,
          toneMappingExposure: 1.1,
        }}
      >
        {/* Near-black deep blue background */}
        <color attach="background" args={["#000510"]} />

        <Suspense fallback={null}>
          <ParticleSystem />

          {/* Bloom — makes particles glow like high-voltage light */}
          <EffectComposer multisampling={0}>
            <Bloom
              intensity={2.6}
              luminanceThreshold={0.04}
              luminanceSmoothing={0.88}
              kernelSize={KernelSize.LARGE}
              mipmapBlur
            />
          </EffectComposer>
        </Suspense>
      </Canvas>
    </div>
  );
}
